// ============================================================
// Main Seed Function
// ============================================================
async function seedSubject(name: string, questions: any[]) {
  const subject = await prisma.subject.findFirst({ where: { name, level: "SHS" } });
  if (!subject) {
    console.log(`  Subject "${name}" not found at SHS level! Skipping.`);
    return;
  }
  let created = 0;
  for (const q of questions) {
    try {
      await prisma.question.create({
        data: {
          level: "SHS",
          examType: "WASSCE",
          subjectId: subject.id,
          topic: q.topic,
          year: q.year,
          questionText: q.questionText,
          optionA: q.optionA,
          optionB: q.optionB,
          optionC: q.optionC,
          optionD: q.optionD,
          correctOption: q.correctOption,
          explanation: q.explanation,
          difficulty: q.difficulty,
        },
      });
      created++;
    } catch (e) {
      // skip duplicates or errors silently
    }
  }
  console.log(`  ${name}: ${created}/${questions.length} questions created`);
}

async function main() {
  console.log("=== Seeding SHS Textbook-Aligned Questions ===");
  console.log(`  Core Mathematics: ${coreMathQuestions.length} questions`);
  console.log(`  Elective Mathematics: ${electiveMathQuestions.length} questions`);
  console.log(`  Integrated Science: ${intScienceQuestions.length} questions`);
  console.log(`  Economics: ${economicsQuestions.length} questions`);
  console.log(`  Total: ${coreMathQuestions.length + electiveMathQuestions.length + intScienceQuestions.length + economicsQuestions.length}`);
  console.log("");

  await seedSubject("Core Mathematics", coreMathQuestions);
  await seedSubject("Elective Mathematics", electiveMathQuestions);
  await seedSubject("Integrated Science", intScienceQuestions);
  await seedSubject("Economics", economicsQuestions);

  console.log("\n=== Seeding Complete ===");
}

main()
  .catch(console.error)
  .finally(() => prisma.$disconnect());
